import{_ as d,C as r,o as n,c as i,j as t,a as o,E as s,ag as p}from"./chunks/framework.HG0H2VLS.js";const f=JSON.parse('{"title":"HeaderGroup","description":"","frontmatter":{},"headers":[],"relativePath":"cc-patterns/header-group.md","filePath":"cc-patterns/header-group.md"}'),c={name:"cc-patterns/header-group.md"};function l(h,e,u,m,g,b){const a=r("ComponentDemo");return n(),i("div",null,[e[0]||(e[0]=t("hr",null,null,-1)),e[1]||(e[1]=t("h2",{id:"title-headergroup",tabindex:"-1"},[o("title: HeaderGroup "),t("a",{class:"header-anchor",href:"#title-headergroup","aria-label":'Permalink to "title: HeaderGroup"'},"​")],-1)),e[2]||(e[2]=t("h1",{id:"headergroup",tabindex:"-1"},[o("HeaderGroup "),t("a",{class:"header-anchor",href:"#headergroup","aria-label":'Permalink to "HeaderGroup"'},"​")],-1)),s(a,{src:"/demos/src/cc/patterns/HeaderGroup/HeaderGroup.html"}),e[3]||(e[3]=p('<h2 id="variant-matrix-verified-from-figma-get-metadata-2026-05-27" tabindex="-1">Variant matrix (verified from Figma <code>get_metadata</code> 2026-05-27) <a class="header-anchor" href="#variant-matrix-verified-from-figma-get-metadata-2026-05-27" aria-label="Permalink to &quot;Variant matrix (verified from Figma `get_metadata` 2026-05-27)&quot;">​</a></h2><p>Two axes: <strong>Device × Type</strong> = 6 variants. <strong>⚠ Figma variant names are partially swapped vs the rendered widths</strong> for the Default and Mobile/Zone Selector rows — see Authoring Bugs.</p><table tabindex="0"><thead><tr><th>Node ID</th><th>Figma label</th><th>Width</th><th>Treated as</th><th>Type</th><th>Composes</th></tr></thead><tbody><tr><td><code>4105:4237</code></td><td>&quot;Device=Mobile, Default&quot;</td><td>1280</td><td><strong>Desktop / Default</strong></td><td>Default</td><td>CCTopNavigation Multizone/Desktop + CCHeader Control/Desktop</td></tr><tr><td><code>4105:4236</code></td><td>&quot;Device=Desktop, Default&quot;</td><td>390</td><td><strong>Mobile / Default</strong></td><td>Default</td><td>CCTopNavigation Multizone/Mobile + CCHeader Control/Mobile</td></tr><tr><td><code>4134:3452</code></td><td>&quot;Device=Desktop, Zone Selector&quot;</td><td>1280</td><td><strong>Desktop / Zone Selector</strong></td><td>Zone Selector</td><td>Default Desktop + open basic Dropdown showing zone list</td></tr><tr><td><code>4134:4066</code></td><td>&quot;Device=Desktop, Zone Selector&quot;</td><td>390</td><td><strong>Mobile / Zone Selector</strong></td><td>Zone Selector</td><td>Default Mobile + same dropdown</td></tr><tr><td><code>4134:4154</code></td><td>&quot;Device=Desktop, User Menu&quot;</td><td>1280</td><td><strong>Desktop / User Menu</strong></td><td>User Menu</td><td>Default Desktop + open Dropdown Type=User menu (ThemeToggle + Icon Navigation Toggle + DropdownItems + Warning Sign Out) anchored to the user block</td></tr><tr><td><code>4135:4114</code></td><td>&quot;Device=Mobile, User Menu&quot;</td><td>390</td><td><strong>Mobile / User Menu</strong></td><td>User Menu</td><td>Default Mobile + same User-menu dropdown</td></tr></tbody></table><p>Per user decision, <strong>width is the source of truth</strong>. Demo HTML uses <code>@media (max-width: 767px)</code> + <code>.demo-frame--mobile</code> for the collapse behaviour — no <code>--mobile</code> modifier class.</p><p>The Zone Selector and User Menu variants are <strong>showcase views</strong>: they show the composed HeaderGroup with a Dropdown component in its open state, overlaying the header chrome. The dropdown markup uses <code>.is-open</code> plus <code>data-dropdown-init=&quot;1&quot;</code> so the Dropdown JS skips the toggle/click-outside logic and leaves the panel visible. In production these would behave like any other Dropdown — closed by default, open on trigger click, close on outside click / Escape.</p><hr><h2 id="css-class-mapping" tabindex="-1">CSS class mapping <a class="header-anchor" href="#css-class-mapping" aria-label="Permalink to &quot;CSS class mapping&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Figma</th><th>CSS</th></tr></thead><tbody><tr><td>Wrapper (<code>CCHeaderGroup</code>)</td><td><code>.cc-header-group</code> (<code>&lt;div&gt;</code>)</td></tr><tr><td><code>CCTopNavigation</code> instance</td><td><code>.cc-top-navigation</code> (CCTopNavigation pattern)</td></tr><tr><td><code>CCHeader</code> instance</td><td><code>.cc-header.cc-header--control</code> (CCHeader pattern)</td></tr><tr><td>Zone Selector dropdown</td><td>Existing <code>.dropdown</code> inside the Breadcrumb&#39;s first list item (composed from Dropdown component). Demo applies <code>.is-open</code> to force open.</td></tr><tr><td>User Menu dropdown</td><td>New: the topNav&#39;s <code>.cc-top-navigation__user</code> button is wrapped in <code>.dropdown.dropdown--user-menu</code> with a sibling <code>.dropdown__panel</code> containing ThemeToggle + Toggle + DropdownItems. Demo applies <code>.is-open</code> to force open.</td></tr></tbody></table><p>CCHeaderGroup itself owns minimal CSS — it&#39;s a thin vertical-stack wrapper around two existing patterns. The Zone Selector and User Menu types reuse the existing Dropdown component; no new CSS in HeaderGroup.css for those variants — they are entirely a composition + open-state demo.</p><hr><h2 id="token-mapping" tabindex="-1">Token mapping <a class="header-anchor" href="#token-mapping" aria-label="Permalink to &quot;Token mapping&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Property</th><th>Token</th></tr></thead><tbody><tr><td>Flex direction</td><td><code>column</code></td></tr><tr><td>Width</td><td><code>100%</code></td></tr><tr><td>Item alignment</td><td><code>stretch</code></td></tr></tbody></table><h3 id="notes-on-composed-height" tabindex="-1">Notes on composed height <a class="header-anchor" href="#notes-on-composed-height" aria-label="Permalink to &quot;Notes on composed height&quot;">​</a></h3><p>Figma shows the CCHeader nested inside CCHeaderGroup Mobile at <code>min-h-[48px]</code>, vs the standalone CCHeader Mobile at <code>min-h-[56px]</code>. <strong>By project decision the composed Header uses the standalone 56px</strong> — the original 48px contextual override was removed (Figma may have been authored inconsistently). The composed children retain their standalone CSS unchanged.</p><hr><h2 id="authoring-bugs-to-flag-to-designer" tabindex="-1">Authoring bugs (to flag to designer) <a class="header-anchor" href="#authoring-bugs-to-flag-to-designer" aria-label="Permalink to &quot;Authoring bugs (to flag to designer)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Issue</th><th>Where</th><th>Resolution</th></tr></thead><tbody><tr><td>Variant labels swapped</td><td>Component set <code>4105:4238</code>. The 1280px-wide variant is named <code>Device=Mobile</code> (should be Desktop); the 390px-wide variant is named <code>Device=Desktop</code> (should be Mobile).</td><td>Code uses <strong>width as truth</strong>. Designer to rename Figma variants.</td></tr><tr><td>Component composed from only the Control type and Multizone topNav</td><td>Figma only ships one composed variant per device (Multizone+Control). Other compositions (Default topNav + Default header, Default topNav + Sub Text header, etc.) are not represented as compiled variants.</td><td>Documented. Consumers compose CCTopNavigation + CCHeader directly for other combinations.</td></tr></tbody></table><hr><h2 id="token-gaps" tabindex="-1">Token gaps <a class="header-anchor" href="#token-gaps" aria-label="Permalink to &quot;Token gaps&quot;">​</a></h2><p>None unique to CCHeaderGroup. Inherits gaps from child patterns (see CCTopNavigation figma-notes for portrait-28px and mobile-gap-18px gaps; CCHeader figma-notes for notification-badge-red gap).</p><hr><h2 id="interactions" tabindex="-1">Interactions <a class="header-anchor" href="#interactions" aria-label="Permalink to &quot;Interactions&quot;">​</a></h2><p>CCHeaderGroup owns no interactions — all interactions live in the composed child patterns (CCTopNavigation Zone Selector dropdown, CCHeader kebab dropdown, etc.).</p><hr><h2 id="responsive-behaviour" tabindex="-1">Responsive behaviour <a class="header-anchor" href="#responsive-behaviour" aria-label="Permalink to &quot;Responsive behaviour&quot;">​</a></h2><p>CCHeaderGroup owns no responsive CSS — all responsive behaviour comes from the child patterns (see CCTopNavigation and CCHeader figma-notes).</p><hr><h2 id="history" tabindex="-1">History <a class="header-anchor" href="#history" aria-label="Permalink to &quot;History&quot;">​</a></h2><ul><li>2026-05-15: Initial compiled pattern scaffold. Built from Figma component set <code>4105:4238</code> (CC Hybrid Design System). 2 variants reduced to a single responsive HTML structure. Figma authoring bug noted (variant names swapped vs widths) — width treated as truth. A contextual mobile-height override (48px composed vs 56px standalone) was initially added per Figma, then removed on 2026-05-18 — composed Header now inherits the standalone 56px.</li><li>2026-05-27: Figma added Type axis with two new types (Zone Selector, User Menu), bringing the variant count to 6 (3 Types × 2 Devices). Both new types are showcase views of the existing Default layout with a Dropdown forced open — Zone Selector anchored to the Breadcrumb&#39;s first list item, User Menu anchored to the topNav user block. Demo HTML uses <code>.is-open</code> + <code>data-dropdown-init=&quot;1&quot;</code> to keep the dropdown panel visible for inspection. No production CSS added — the new types are composition + open-state.</li></ul>',29))])}const C=d(c,[["render",l]]);export{f as __pageData,C as default};
